namespace sv_34baacaf45a54e1bb0a3e4ccddac0957.Services;

/// <summary>
/// Scoped service (per circuit) that polls for low-stock alerts and
/// notifies every subscribed component via the OnChange event.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly Lock _lock = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Raised on the thread-pool — subscribers must use InvokeAsync(StateHasChanged).
    /// </summary>
    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query returning items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call
        return Task.FromResult(Random.Shared.Next(0, 16));
    }

    /// <summary>
    /// Begin polling every 10 seconds for the given warehouse.
    /// Stops any previous poll loop first.
    /// </summary>
    public void StartPolling(string warehouseId)
    {
        StopPolling();

        _cts = new CancellationTokenSource();
        var token = _cts.Token;
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = PollLoopAsync(warehouseId, token);
    }

    public void StopPolling()
    {
        lock (_lock)
        {
            _cts?.Cancel();
            _timer?.Dispose();
            _timer = null;
        }
    }

    private async Task PollLoopAsync(string warehouseId, CancellationToken ct)
    {
        try
        {
            // Fetch immediately on start
            LatestLowStockCount = await GetLowStockCountAsync(warehouseId);
            OnChange?.Invoke();

            while (_timer is not null && await _timer.WaitForNextTickAsync(ct))
            {
                LatestLowStockCount = await GetLowStockCountAsync(warehouseId);
                OnChange?.Invoke();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when StopPolling is called
        }
    }

    public void Dispose()
    {
        StopPolling();
        _cts?.Dispose();
    }
}

