@inject CascadingValueSource<WarehouseInfo> WarehouseSource

<select class="form-select form-select-sm"
        style="width: 200px;"
        value="@_selectedId"
        @onchange="OnWarehouseChanged">
    @foreach (var (id, name) in WarehouseInfo.AvailableWarehouses)
    {
        <option value="@id">@name</option>
    }
</select>

@code {
    private string _selectedId = "WH-001";

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? "WH-001";
        var match = WarehouseInfo.AvailableWarehouses
            .First(w => w.Id == _selectedId);

        await WarehouseSource.NotifyChangedAsync(
            new WarehouseInfo
            {
                SelectedWarehouseId = match.Id,
                SelectedWarehouseName = match.Name
            });
    }
}

@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LatestLowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill">@AlertService.LatestLowStockCount</span>
}
else
{
    <span class="badge bg-secondary rounded-pill">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Background thread fires OnChange → must use InvokeAsync
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
    }
}

