@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p>Currently viewing: <strong>@Warehouse?.SelectedWarehouseName</strong></p>

<div class="card mt-3" style="max-width: 320px;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text display-4 text-center">
            <AlertBadge @rendermode="InteractiveServer" />
        </p>
        <p class="text-muted small">Refreshes every 10 seconds</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private string _currentWarehouseId = string.Empty;
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    protected override void OnParametersSet()
    {
        var warehouseId = Warehouse?.SelectedWarehouseId ?? "WH-001";

        // Restart polling when the warehouse changes
        if (_currentWarehouseId != warehouseId)
        {
            _currentWarehouseId = warehouseId;
            AlertService.StartPolling(warehouseId);
        }
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
        AlertService.StopPolling();
    }
}

